func (o *Maintenance) Preload(name string, retrieved any) error {
	if o == nil {
		return nil
	}

	switch name {
	case "User":
		rel, ok := retrieved.(*User)
		if !ok {
			return fmt.Errorf("maintenance cannot load %T as %q", retrieved, name)
		}

		o.R.User = rel

		if rel != nil {
			rel.R.Maintenances = MaintenanceSlice{o}
		}
		return nil
	case "MaintenanceStatusPages":
		rels, ok := retrieved.(MaintenanceStatusPageSlice)
		if !ok {
			return fmt.Errorf("maintenance cannot load %T as %q", retrieved, name)
		}

		o.R.MaintenanceStatusPages = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Maintenance = o
			}
		}
		return nil
	case "MaintenanceTimeslots":
		rels, ok := retrieved.(MaintenanceTimeslotSlice)
		if !ok {
			return fmt.Errorf("maintenance cannot load %T as %q", retrieved, name)
		}

		o.R.MaintenanceTimeslots = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Maintenance = o
			}
		}
		return nil
	case "MonitorMaintenances":
		rels, ok := retrieved.(MonitorMaintenanceSlice)
		if !ok {
			return fmt.Errorf("maintenance cannot load %T as %q", retrieved, name)
		}

		o.R.MonitorMaintenances = rels

		for _, rel := range rels {
			if rel != nil {
				rel.R.Maintenance = o
			}
		}
		return nil
	default:
		return fmt.Errorf("maintenance has no relationship %q", name)
	}
}

