// LoadUser loads the maintenance's User into the .R struct
func (o *Maintenance) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.User = nil

	related, err := o.User(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.Maintenances = MaintenanceSlice{o}

	o.R.User = related
	return nil
}

// LoadUser loads the maintenance's User into the .R struct
func (os MaintenanceSlice) LoadUser(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	users, err := os.User(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range users {

			if !(o.UserID == rel.ID) {
				continue
			}

			rel.R.Maintenances = append(rel.R.Maintenances, o)

			o.R.User = rel
			break
		}
	}

	return nil
}

