type maintenanceJoins[Q dialect.Joinable] struct {
	typ                    string
	User                   modAs[Q, userColumns]
	MaintenanceStatusPages modAs[Q, maintenanceStatusPageColumns]
	MaintenanceTimeslots   modAs[Q, maintenanceTimeslotColumns]
	MonitorMaintenances    modAs[Q, monitorMaintenanceColumns]
}

func (j maintenanceJoins[Q]) aliasedAs(alias string) maintenanceJoins[Q] {
	return buildMaintenanceJoins[Q](buildMaintenanceColumns(alias), j.typ)
}

func buildMaintenanceJoins[Q dialect.Joinable](cols maintenanceColumns, typ string) maintenanceJoins[Q] {
	return maintenanceJoins[Q]{
		typ: typ,
		User: modAs[Q, userColumns]{
			c: Users.Columns,
			f: func(to userColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Users.Name().As(to.Alias())).On(
						to.ID.EQ(cols.UserID),
					))
				}

				return mods
			},
		},
		MaintenanceStatusPages: modAs[Q, maintenanceStatusPageColumns]{
			c: MaintenanceStatusPages.Columns,
			f: func(to maintenanceStatusPageColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, MaintenanceStatusPages.Name().As(to.Alias())).On(
						to.MaintenanceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		MaintenanceTimeslots: modAs[Q, maintenanceTimeslotColumns]{
			c: MaintenanceTimeslots.Columns,
			f: func(to maintenanceTimeslotColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, MaintenanceTimeslots.Name().As(to.Alias())).On(
						to.MaintenanceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
		MonitorMaintenances: modAs[Q, monitorMaintenanceColumns]{
			c: MonitorMaintenances.Columns,
			f: func(to monitorMaintenanceColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, MonitorMaintenances.Name().As(to.Alias())).On(
						to.MaintenanceID.EQ(cols.ID),
					))
				}

				return mods
			},
		},
	}
}
